import axios from 'axios';

const API_BASE_URL = 'http://localhost:5033/api';

const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
    'Accept': 'application/json'
  }
});

// Request Interceptor - Attach JWT token
api.interceptors.request.use(
  (config) => {
    const token = sessionStorage.getItem('token') || localStorage.getItem('token');
    if (token) {
      config.headers = config.headers || {};
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);

// Response Interceptor
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      console.error('Unauthorized - clearing tokens');
      sessionStorage.removeItem('token');
      localStorage.removeItem('token');
    }
    return Promise.reject(error);
  }
);

// ===================== MONGODB AUTH API (PRIMARY) =====================
export const mongoAuthAPI = {
  login: async (email, password) => {
    console.log('🔐 MongoDB Login:', { email });
    return api.post('/mongo/auth/login', { email, password });
  },

  register: async (fullName, email, mobile, password, gender) => {
    console.log('📝 MongoDB Register:', { fullName, email, mobile, gender });
    return api.post('/mongo/auth/register', { fullName, email, mobile, password, gender });
  },

  requestOtp: async (mobile) => {
    console.log('📱 MongoDB Request OTP:', { mobile });
    return api.post('/mongo/auth/request-otp', { mobile });
  },

  verifyOtp: async (mobile, otp) => {
    console.log('✅ MongoDB Verify OTP:', { mobile, otp });
    return api.post('/mongo/auth/verify-otp', { mobile, otp });
  },

  requestEmailOtp: async (email) => {
    console.log('📧 MongoDB Request Email OTP:', { email });
    return api.post('/mongo/auth/request-email-otp', { email });
  },

  verifyEmailOtp: async (email, otp) => {
    console.log('✅ MongoDB Verify Email OTP:', { email, otp });
    return api.post('/mongo/auth/verify-email-otp', { email, otp });
  },

  getProfile: () => {
    console.log('👤 MongoDB Get Profile');
    return api.get('/mongo/user/profile');
  },

  updateProfile: (profileData) => {
    console.log('✏️ MongoDB Update Profile:', profileData);
    return api.put('/mongo/user/profile', profileData);
  }
};

// ✅ USE MONGODB AUTH AS PRIMARY AUTH
export const authAPI = mongoAuthAPI;

// ===================== MONGODB PRODUCTS API =====================
export const productsAPI = {
  // READ Operations
  getAll: () => {
    console.log('📦 MongoDB Get All Products');
    return api.get('/mongo/products');
  },

  search: (query) => {
    console.log('🔍 MongoDB Search Products:', query);
    return api.get('/mongo/products/search', { params: { query: query || '' } });
  },

  getById: (id) => {
    console.log('📦 MongoDB Get Product by ID:', id);
    return api.get(`/mongo/products/${id}`);
  },

  // WRITE Operations (Admin only)
  create: (productData) => {
    console.log('➕ MongoDB Create Product:', productData);
    return api.post('/mongo/products', productData);
  },

  update: (id, productData) => {
    console.log('✏️ MongoDB Update Product:', id, productData);
    return api.put(`/mongo/products/${id}`, productData);
  },

  delete: (id) => {
    console.log('🗑️ MongoDB Delete Product:', id);
