  saveAll: async (addresses) => {
    console.log('💾 MongoDB Save All Addresses:', addresses.length);
    const results = [];
    for (const addr of addresses) {
      try {
        let result;
        if (addr.id || addr.Id) {
          result = await addressAPI.update(addr.id || addr.Id, addr);
        } else {
          result = await addressAPI.add(addr);
        }
        results.push(result);
      } catch (e) {
