/**
 * Extract MongoDB ObjectId from various object formats
 */
export const getMongoId = (obj) => {
  if (!obj) return null;

  // Check _id field (most common)
  if (obj._id) {
    if (typeof obj._id === 'object' && obj._id.$oid) return obj._id.$oid;
    if (typeof obj._id === 'string' && /^[0-9a-f]{24}$/i.test(obj._id)) return obj._id;
  }

  // Check id field
  if (obj.id && typeof obj.id === 'string' && /^[0-9a-f]{24}$/i.test(obj.id)) return obj.id;

  // Check Id field (PascalCase)
  if (obj.Id && typeof obj.Id === 'string' && /^[0-9a-f]{24}$/i.test(obj.Id)) return obj.Id;

  // Check mongoId field
  if (obj.mongoId && /^[0-9a-f]{24}$/i.test(obj.mongoId)) return obj.mongoId;

  console.warn('⚠️ Could not extract MongoDB ObjectId from object:', obj);
  return null;
};

/**
 * Validate MongoDB ObjectId format
 */
export const isValidMongoId = (id) => {
  if (!id || typeof id !== 'string') return false;
  return /^[0-9a-f]{24}$/i.test(id);
};

/**
 * Get User ID from JWT token
 */
export const getUserIdFromToken = () => {
  const token = sessionStorage.getItem('token') || localStorage.getItem('token');
  if (!token) {
    console.warn('⚠️ No token found in storage');
    return null;
  }

  try {
    const payload = JSON.parse(atob(token.split('.')[1]));

    // Extract user ID from various possible claim names
    const userId = payload.nameid || 
                   payload['http://schemas.xmlsoap.org/ws/2005/05/identity/claims/nameidentifier'] ||
                   payload.sub ||
                   payload.userId ||
                   payload.id;

    console.log('✅ User ID from token:', userId);
    return userId;
  } catch (error) {
    console.error('❌ Error extracting user ID from token:', error);
    return null;
  }
};

/**
 * Get User Type from JWT token
 */
export const getUserType = () => {
  const token = sessionStorage.getItem('token') || localStorage.getItem('token');
  if (!token) return null;

  try {
    const payload = JSON.parse(atob(token.split('.')[1]));
    return payload.UserType || 'MongoDB';
  } catch (error) {
    console.error('Error decoding token:', error);
    return 'MongoDB';
  }
};

/**
 * Check if user is Admin
 */
export const isAdmin = () => {
  const token = sessionStorage.getItem('token') || localStorage.getItem('token');
  if (!token) return false;

  try {
    const payload = JSON.parse(atob(token.split('.')[1]));
    const role = payload.role || 
                 payload['http://schemas.microsoft.com/ws/2008/06/identity/claims/role'];
    return role === 'Admin' || role === '1';
  } catch (error) {
    return false;
  }
};

/**
 * Format date for API requests
 */
export const formatDateForAPI = (date) => {
  if (!date) return null;
  if (typeof date === 'string') return date;
  return date.toISOString().split('T')[0];
};

/**
 * Parse API response
 */
export const parseAPIResponse = (response) => {
  if (!response) return null;
  return response.data || response;
};

